params.script:
var yoken  = $runner.getModuleResult("OpenAI_用件");
var kibobi = $runner.getModuleResult("OpenAI_希望日");
if (!yoken) yoken = "";
if (!kibobi) kibobi = "";

if (yoken === "予約") {
  $runner.setResult("予約");
} else if (yoken === "変更・キャンセル") {
  if (kibobi === "なし" || kibobi === "NONE" || kibobi === "") {
    $runner.setResult("キャンセル");
  } else {
    $runner.setResult("変更");
  }
} else {
  $runner.setResult("その他確認");
}
